import importlib.resources as _ir
resource_filename = lambda pkg, path: str(_ir.files(pkg).joinpath(path))

import gi
gi.require_version('Gtk', '3.0')  # @UndefinedVariable
from gi.repository import Gtk  # @UnresolvedImport

import matplotlib
from matplotlib.figure import Figure
from matplotlib.backends.backend_gtk3cairo import FigureCanvasGTK3Cairo as FigureCanvasGTK
from matplotlib.backends.backend_gtk3 import NavigationToolbar2GTK3 as NavigationToolbar

from pyxrd.generic.views import BaseView

class RefinerView(BaseView):
    """
        A view for the Refiner object
    """
    
    builder = resource_filename(__name__, "glade/refine_results.glade")
    top = "window_refine_results"
    modal = True

    graph_parent = "plot_box"

    def __init__(self, *args, **kwargs):
        BaseView.__init__(self, *args, **kwargs)

        self.graph_parent = self[self.graph_parent]

        self.get_toplevel().set_transient_for(self.parent.get_toplevel())

        self.setup_matplotlib_widget()

    def update_labels(self, initial, best, last, elapsed=None):
        self["initial_residual"].set_text("%f" % initial)
        self["best_residual"].set_text("%f" % best)
        self["last_residual"].set_text("%f" % last)
        if elapsed is not None:
            mins, secs = divmod(int(elapsed), 60)
            self["elapsed_time"].set_text("%d:%02d" % (mins, secs))

    def setup_matplotlib_widget(self):
        # TODO Create a mixin for this kind of thing!!
        #style = Gtk.Style()
        self.figure = Figure(dpi=96)

        self.figure.subplots_adjust(left=0.12, right=0.88, top=0.92, bottom=0.12, hspace=0.4, wspace=0.4)

        self.canvas = FigureCanvasGTK(self.figure)

        box = Gtk.VBox()
        box.pack_start(NavigationToolbar(self.canvas), False, True, 0)
        box.pack_start(self.canvas, True, True, 0)
        self.graph_parent.add(box)
        self.graph_parent.show_all()

        cdict = {'red': ((0.0, 0.0, 0.0),
                         (0.5, 1.0, 1.0),
                         (1.0, 0.0, 0.0)),
                'green': ((0.0, 0.0, 0.0),
                         (0.5, 1.0, 1.0),
                         (1.0, 0.0, 0.0)),
                'blue': ((0.0, 0.0, 0.0),
                         (0.5, 1.0, 1.0),
                         (1.0, 0.0, 0.0))}
        self.wbw_cmap = matplotlib.colors.LinearSegmentedColormap('WBW', cdict, 256)

    def show_plot_popup(self):
        import io

        buf = io.BytesIO()
        self.figure.savefig(buf, format='svg', bbox_inches='tight')
        svg_bytes = buf.getvalue()

        content_widget = None
        try:
            import gi
            gi.require_version('Rsvg', '2.0')
            from gi.repository import Rsvg

            handle = Rsvg.Handle.new_from_data(svg_bytes)
            try:
                ok, svg_w, svg_h = handle.get_intrinsic_size_in_pixels()
                if not ok:
                    raise RuntimeError("no intrinsic size")
            except AttributeError:
                dim = handle.get_dimensions()
                svg_w, svg_h = float(dim.width), float(dim.height)
            svg_w, svg_h = max(1, int(svg_w)), max(1, int(svg_h))

            drawing_area = Gtk.DrawingArea()
            drawing_area.set_size_request(svg_w, svg_h)

            def on_draw(widget, cr):
                try:
                    vp = Rsvg.Rectangle()
                    vp.x, vp.y, vp.width, vp.height = 0, 0, svg_w, svg_h
                    handle.render_document(cr, vp)
                except AttributeError:
                    handle.render_cairo(cr)
                return False

            drawing_area.connect('draw', on_draw)
            content_widget = drawing_area
        except Exception:
            pass

        if content_widget is None:
            # PNG fallback
            from gi.repository import GdkPixbuf
            buf2 = io.BytesIO()
            self.figure.savefig(buf2, format='png', dpi=150, bbox_inches='tight')
            buf2.seek(0)
            loader = GdkPixbuf.PixbufLoader.new_with_type('png')
            loader.write(buf2.read())
            loader.close()
            content_widget = Gtk.Image.new_from_pixbuf(loader.get_pixbuf())

        def on_save_clicked(btn):
            dialog = Gtk.FileChooserDialog(
                title="Save SVG",
                parent=win,
                action=Gtk.FileChooserAction.SAVE,
            )
            dialog.add_button("Cancel", Gtk.ResponseType.CANCEL)
            dialog.add_button("Save", Gtk.ResponseType.OK)
            dialog.set_current_name("parameter_space.svg")
            filt = Gtk.FileFilter()
            filt.set_name("SVG files (*.svg)")
            filt.add_pattern("*.svg")
            dialog.add_filter(filt)
            dialog.set_do_overwrite_confirmation(True)
            if dialog.run() == Gtk.ResponseType.OK:
                path = dialog.get_filename()
                if not path.lower().endswith('.svg'):
                    path += '.svg'
                with open(path, 'wb') as f:
                    f.write(svg_bytes)
            dialog.destroy()

        save_btn = Gtk.Button(label="Save SVG\u2026")
        save_btn.connect('clicked', on_save_clicked)

        btn_box = Gtk.HBox()
        btn_box.pack_end(save_btn, False, False, 6)

        scroll = Gtk.ScrolledWindow()
        scroll.set_policy(Gtk.PolicyType.AUTOMATIC, Gtk.PolicyType.AUTOMATIC)
        scroll.add(content_widget)

        vbox = Gtk.VBox()
        vbox.pack_start(scroll, True, True, 0)
        vbox.pack_start(btn_box, False, False, 4)

        win = Gtk.Window(title="Parameter space")
        win.set_default_size(1200, 900)
        win.set_transient_for(self.get_toplevel())
        win.add(vbox)
        win.show_all()

    pass # end of class